import { Component, Event, EventEmitter, Fragment, h, Prop } from '@stencil/core';

@Component({
  tag: 'wdpr-media-player-control',
  shadow: true,
})
export class WdprMediaPlayerControl {
  @Prop() playing = false;
  @Prop() muted = false;
  @Prop() isFullscreen = false;
  @Prop() captionsEnabled = false;
  @Prop() currentTime = 0;
  @Prop() duration = 0;
  @Prop() showControls = true;
  @Prop() showTime = true;
  @Prop() showCaptionsToggle = true;
  @Prop() showMuteToggle = true;
  @Prop() showFullscreenButton = true;
  @Prop() showPlayToggleOnControl = true;
  @Prop() showProgressBar = true;
  @Prop() showAudioChip = false;
  @Prop() vertical = false;
  @Prop() loading = false;
  @Event({ bubbles: true, composed: true }) wdprFullscreenToggle!: EventEmitter<void>;

  private _formatTime(sec: number) {
    if (!Number.isFinite(sec) || sec < 0) return '0:00';
    const s = Math.floor(sec % 60)
      .toString()
      .padStart(2, '0');
    const m = Math.floor((sec / 60) % 60).toString();
    const h = Math.floor(sec / 3600);

    return h > 0 ? `${h}:${m.padStart(2, '0')}:${s}` : `${m}:${s}`;
  }

  render() {
    return (
      <div class="absolute inset-0">
        <div class={`absolute inset-0 z-30 flex justify-center pointer-events-none ${!this.isFullscreen && 'items-center'}`}>
          {this.isFullscreen ? (
            <div class="absolute flex justify-between w-full pointer-events-auto">
              <button aria-label="Go back" class="cursor-pointer m-200 ml-300 p-025 rounded-pill text-icon-actionable-inverse-default bg-surface-actionable-alt-default-a78 hover:bg-surface-actionable-alt-hover-a88 active:bg-surface-actionable-alt-pressed elevation-xsmall-soft focus:outline-none focus-visible:outline-037 focus-visible:outline-stroke-actionable-alt-focused focus-visible:outline-solid focus-visible:outline-offset-2" onClick={() => this.wdprFullscreenToggle.emit()}>
                <wdpr-icon-library size="large" icon="back-thick" />
              </button>

              <button aria-label="Exit fullscreen" class="cursor-pointer m-200 mr-300 p-025 rounded-pill text-icon-actionable-inverse-default bg-surface-actionable-alt-default-a78 hover:bg-surface-actionable-alt-hover-a88 active:bg-surface-actionable-alt-pressed elevation-xsmall-soft focus:outline-none focus-visible:outline-037 focus-visible:outline-stroke-actionable-alt-focused focus-visible:outline-solid focus-visible:outline-offset-2" onClick={() => this.wdprFullscreenToggle.emit()}>
                <wdpr-icon-library size="large" icon="close-reversed" />
              </button>
            </div>
          ) : (
            !this.loading && (
              <div class="pointer-events-auto">
                <wdpr-media-player-control-play-toggle playing={this.playing} />
              </div>
            )
          )}
        </div>

        {this.showControls ? (
          <div class="absolute inset-0 z-20">
            <div
              class={{
                'absolute inset-x-0 bottom-0': true,
                'h-dimension-1000': this.vertical,
              }}
            >
              <div
                class={{
                  'relative p-100 flex flex-col gap-100 bg-surface-actionable-alt-default-a78': true,
                  'pb-000': this.vertical,
                }}
              >
                {this.showProgressBar && <wdpr-media-player-control-progress-bar currentTime={this.currentTime} duration={this.duration} />}

                <div class="flex items-center justify-between gap-100">
                  <div class="flex items-center gap-100">
                    {this.showPlayToggleOnControl && <wdpr-media-player-control-play-toggle playing={this.playing} variant="control" />}
                    {this.showTime && (
                      <Fragment>
                        <span class={timeTextClasses}>{this._formatTime(this.currentTime)}</span>
                        <span class={timeTextClasses}>{this._formatTime(this.duration)}</span>
                      </Fragment>
                    )}
                  </div>

                  <div class="flex items-center gap-100">
                    {this.showCaptionsToggle && <wdpr-media-player-control-captions-toggle enabled={this.captionsEnabled} />}
                    {this.showMuteToggle && <wdpr-media-player-control-mute-toggle muted={this.muted} variant="control" />}
                    {this.showFullscreenButton && !this.isFullscreen && <wdpr-media-player-control-fullscreen-toggle />}
                  </div>
                </div>
              </div>
            </div>
          </div>
        ) : null}
      </div>
    );
  }
}

const timeTextClasses = 'select-none text-body-medium text-icon-actionable-inverse-default';
